function parseJsonSafe(value, fallback) {
  try { return value ? JSON.parse(value) : fallback; } catch { return fallback; }
}
function toDateMs(value) {
  if (!value) return null;
  const d = new Date(value);
  const ms = d.getTime();
  return Number.isNaN(ms) ? null : ms;
}
function inRange(ms, startMs, endMs, nowMs) {
  if (ms === null) return false;
  const afterStart = startMs === null ? true : ms >= startMs;
  const beforeEnd = endMs === null ? ms <= nowMs : ms < endMs;
  return afterStart && beforeEnd;
}

const siteSlug = String($env.SITE_SLUG || '').toLowerCase().trim();
if (!siteSlug) throw new Error('Missing SITE_SLUG env var for publish scheduler');
const settingsDoc = (($('Fetch siteSettings publishing config').item.json || {}).result) || {};
const publishing = settingsDoc.publishing || {};
const entitlement = settingsDoc.entitlement || {};
const recent = Array.isArray((($('Fetch recent published articles').item.json || {}).result)) ? $('Fetch recent published articles').item.json.result : [];
const queue = Array.isArray((($('Fetch ready_to_publish queue').item.json || {}).result)) ? $('Fetch ready_to_publish queue').item.json.result : [];

const rules = Array.isArray(publishing.cadenceRules) ? publishing.cadenceRules : [];
if (!rules.length) throw new Error('Missing publishing.cadenceRules in siteSettings');
const now = Date.now();

const activeRule = rules.find((rule) => {
  const start = toDateMs(rule.startAt);
  const end = toDateMs(rule.endAt);
  const afterStart = start === null ? true : now >= start;
  const beforeEnd = end === null ? true : now < end;
  return afterStart && beforeEnd;
}) || rules[rules.length - 1];

if (!activeRule || !queue.length) return [];
const intervalMs = activeRule.perMinutes ? Number(activeRule.perMinutes) * 60_000 : Number(activeRule.perDays || 1) * 86_400_000;
const maxPublishes = Math.max(1, Number(activeRule.maxPublishes || 1));
const maxPerRun = Math.max(1, Number(publishing.maxPublishesPerRun || 1));
const revalidateEnabled = publishing.revalidateEnabled !== false && String($env.PUBLISH_REVALIDATE_ENABLED || 'true') !== 'false';

const windowStart = now - intervalMs;
const publishedInWindow = recent.filter((article) => {
  const ms = toDateMs(article.publishedAt);
  return ms !== null && ms >= windowStart && ms <= now;
}).length;

const planStatus = String(entitlement.status || 'active').toLowerCase();
if (planStatus !== 'active') return [];
const planMonthlyQuota = Math.max(0, Number(entitlement.monthlyQuota || publishing.planMonthlyQuota || 0));
const planPeriodStartMs = toDateMs(entitlement.periodStart || publishing.quotaPeriodStart);
const planPeriodEndMs = toDateMs(entitlement.periodEnd || publishing.quotaPeriodEnd);
const publishedInPlanPeriod = recent.filter((article) => {
  const ms = toDateMs(article.publishedAt);
  return inRange(ms, planPeriodStartMs, planPeriodEndMs, now);
}).length;
const monthlyRemaining = planMonthlyQuota > 0 ? Math.max(0, planMonthlyQuota - publishedInPlanPeriod) : Number.MAX_SAFE_INTEGER;
if (monthlyRemaining <= 0) return [];

const cadenceRemaining = Math.max(0, maxPublishes - publishedInWindow);
if (cadenceRemaining <= 0) return [];

const selected = queue
  .slice()
  .sort((a, b) => {
    const qaDiff = Number(b.qaScore || 0) - Number(a.qaScore || 0);
    if (qaDiff !== 0) return qaDiff;
    return String(a.qaPassedAt || '').localeCompare(String(b.qaPassedAt || ''));
  })
  .slice(0, Math.min(cadenceRemaining, monthlyRemaining, maxPerRun));

const existingSeqMax = recent.reduce((max, item) => Math.max(max, Number(item.publishSequence || 0)), 0);
const publishedAtIso = new Date().toISOString();

return selected.map((article, index) => ({
  json: {
    ...article,
    siteSlug: article.siteSlug || siteSlug,
    publishedAtIso,
    publishSequence: existingSeqMax + index + 1,
    activeCadenceRule: activeRule,
    quotaRemaining: cadenceRemaining,
    publishedInWindow,
    revalidateEnabled,
    planMonthlyQuota,
    publishedInPlanPeriod,
    monthlyRemaining
  }
}));

